    "coderabbit@claude-plugins-official": true,
    "everything-claude-code@everything-claude-code": true,
    "codex@openai-codex": true
  },
  "extraKnownMarketplaces": {
    "superpowers-marketplace": {
      "source": {
        "source": "github",
        "repo": "obra/superpowers-marketplace"
      }
    },
    "bst-cc-plugins": {
      "source": {
        "source": "git",
